package main

import (
	"html"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: log search query with client info
	log.Printf("SEARCH_ANALYTICS: keyword=%q method=%s remote_addr=%s user_agent=%q",
		keyword, r.Method, r.RemoteAddr, r.UserAgent())

	// Set HTML content type header
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Generate HTML response with properly escaped keyword
	response := `<!DOCTYPE html>
<html>
<head>
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: ` + safeKeyword + `</h2>
</body>
</html>`

	w.Write([]byte(response))
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	log.Println("Starting product search server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

