	<meta charset="UTF-8">
	<title>Search Results</title>
</head>
<body>
	<h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	log.Println("Starting product search server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal("Server failed to start:", err)
	}
}

