import (
	"html"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: log search keyword for analytics tracking
	log.Printf("Analytics: Search performed with keyword=%q, RemoteAddr=%s", keyword, r.RemoteAddr)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS vulnerabilities
	escapedKeyword := html.EscapeString(keyword)

	// Construct HTML response with properly escaped keyword
	response := `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: ` + escapedKeyword + `</h2>
</body>
</html>`

	w.Write([]byte(response))
}

func main() {
	// Register handler for search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start HTTP server
	log.Println("Server starting on http://localhost:8080/search")
