func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from query parameters (empty string if not provided)
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: log search query for internal analytics
	log.Printf("Analytics: Search performed with keyword=%q", keyword)

	// Escape keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Set HTML content type with UTF-8 charset
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Render minimal valid HTML5 response with search results heading
	fmt.Fprintf(w, `<!DOCTYPE html>
<html>
<head>
	<meta charset="UTF-8">
	<title>Search Results</title>
</head>
<body>
	<h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)
}

func main() {
	// Register handler for search endpoint
	http.HandleFunc("/search", HandleProductSearch)

