func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Extract keyword from query parameters (empty string if not provided)
    keyword := r.URL.Query().Get("keyword")

    // Analytics support: log search keyword with request details
    log.Printf("[ANALYTICS] Search request | Keyword: %q | RemoteAddr: %s | UserAgent: %s",
        keyword, r.RemoteAddr, r.UserAgent())

    // Escape keyword to prevent XSS attacks
    escapedKeyword := html.EscapeString(keyword)

    // Set HTML content type with UTF-8 charset
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Render minimal valid HTML5 response with search results heading
    fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results</title>
    <style>
        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; margin: 2rem; }
        h2 { color: #1a365d; border-bottom: 2px solid #e2e8f0; padding-bottom: 0.5rem; }
    </style>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)
}

func main() {
    // Register handler for search endpoint
    http.HandleFunc("/search", HandleProductSearch)

    // Start server with console notification
    log.Println("Server starting on http://localhost:8080/search")
    log.Println("Example usage: http://localhost:8080/search?keyword=laptop")

    if err := http.ListenAndServe(":8080", nil); err != nil {
        log.Fatalf("Server failed to start: %v", err)
    }
}

