package main

import (
	"html"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: log search query for analytics tracking
	log.Printf("Search analytics - keyword: %q, remote_addr: %s", keyword, r.RemoteAddr)

	// Set Content-Type header to HTML with UTF-8 charset
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape keyword to prevent XSS vulnerabilities
	escapedKeyword := html.EscapeString(keyword)

	// Construct HTML response with properly escaped keyword
	response := `<!DOCTYPE html>
<html>
<head>
<title>Product Search Results</title>
</head>
<body>
<h2>Search Results: ` + escapedKeyword + `</h2>
</body>
</html>`

	w.Write([]byte(response))
}

