import (
	"fmt"
	"html"
	"log"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from query parameters (handles missing parameter gracefully)
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: log search keyword for monitoring/analytics purposes
	log.Printf("Analytics: Search performed | keyword=%q | remote_addr=%s", keyword, r.RemoteAddr)

	// Escape keyword to prevent XSS vulnerabilities
	escapedKeyword := html.EscapeString(keyword)

	// Set proper HTML content type header
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Generate minimal valid HTML response with required heading format
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<title>Search Results</title>
</head>
<body>
	<h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)
}

func main() {
	// Register handler for search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start HTTP server with analytics-ready logging
	log.Println("Server starting on http://localhost:8080")
	log.Println("Test with: http://localhost:8080/search?keyword=go+lang")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

